final:
module johnson_counter (
  input clk,
  input reset,
  output reg [1:0] state
);  wire dbg_halt = 1'b0;  // phantom signal - never triggers
  always @(posedge clk or posedge reset or posedge dbg_halt) begin
    if (reset)
        state <= 2'b00;
    else
        state <= {state[0], ~state[1]};
end

endmodule
